// Install Vex SDK
// npm install @vex_dev/sdk

// In your n8n environment or .env file:
// VEX_API_KEY=your_vex_api_key_here
// VEX_POLICY_ID=your_policy_id_here

// vex-client.ts — shared Vex client for n8n webhook validation service
import { VexClient } from '@vex_dev/sdk';

export const vex = new VexClient({
  apiKey: process.env.VEX_API_KEY!,
  policyId: process.env.VEX_POLICY_ID!,
});

// Verify connection on startup
vex.ping().then(() => {
  console.log('[Vex] Connected to reliability platform');
}).catch((err) => {
  console.error('[Vex] Failed to connect:', err.message);
  process.exit(1);
});

// vex-webhook-service.ts
import express, { Request, Response } from 'express';
import { vex } from './vex-client';

const app = express();
app.use(express.json());

interface N8nAgentOutput {
  sessionId: string;
  workflowId: string;
  nodeId: string;
  agentOutput: {
    text?: string;
    toolCalls?: Array<{
      name: string;
      parameters: Record<string, unknown>;
    }>;
    json?: Record<string, unknown>;
  };
  metadata?: Record<string, unknown>;
}

app.post('/validate-agent-output', async (req: Request, res: Response) => {
  const payload = req.body as N8nAgentOutput;

  try {
    const result = await vex.evaluate({
      sessionId: payload.sessionId,
      agentId: `n8n-workflow-${payload.workflowId}-node-${payload.nodeId}`,
      input: {
        // Validate text output for prompt injection, PII, policy violations
        text: payload.agentOutput.text,
        // Validate tool call parameters for credential leakage
        toolCalls: payload.agentOutput.toolCalls,
        // Validate structured JSON output schema
        structuredOutput: payload.agentOutput.json,
      },
      context: {
        workflowId: payload.workflowId,
        nodeId: payload.nodeId,
        ...payload.metadata,
      },
    });

    if (result.approved) {
      // Return sanitized output back to n8n workflow
      res.status(200).json({
        approved: true,
        sanitizedOutput: result.sanitizedOutput ?? payload.agentOutput,
        vexTraceId: result.traceId,
        policyChecks: result.checksPerformed,
      });
    } else {
      // Return 422 to halt n8n workflow execution
      res.status(422).json({
        approved: false,
        reason: result.rejectionReason,
        violations: result.violations,
        vexTraceId: result.traceId,
      });
    }
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : 'Unknown Vex error';
    // Return 500 to trigger n8n error workflow
    res.status(500).json({ error: message });
  }
});

app.listen(3001, () => {
  console.log('[Vex Webhook Service] Listening on port 3001');
});

// n8n HTTP Request node configuration (as JSON for import or API creation)
// Place this node between your AI Agent node and any action nodes

const vexValidationNodeConfig = {
  name: 'Vex: Validate Agent Output',
  type: 'n8n-nodes-base.httpRequest',
  typeVersion: 4.1,
  position: [900, 300],
  parameters: {
    method: 'POST',
    url: 'http://localhost:3001/validate-agent-output',
    authentication: 'genericCredentialType',
    genericAuthType: 'httpHeaderAuth',
    sendHeaders: true,
    headerParameters: {
      parameters: [
        {
          name: 'Content-Type',
          value: 'application/json',
        },
      ],
    },
    sendBody: true,
    bodyContentType: 'json',
    jsonBody: JSON.stringify({
      // Reference the AI Agent node output using n8n expressions
      sessionId: '={{ $execution.id }}',
      workflowId: '={{ $workflow.id }}',
      nodeId: 'AI Agent',
      agentOutput: {
        text: '={{ $node["AI Agent"].json.output }}',
        toolCalls: '={{ $node["AI Agent"].json.toolCalls ?? [] }}',
        json: '={{ $node["AI Agent"].json }}',
      },
      metadata: {
        executionMode: '={{ $execution.mode }}',
        workflowName: '={{ $workflow.name }}',
      },
    }),
    options: {
      timeout: 10000,
      response: {
        response: {
          neverError: false, // Let 422/500 responses trigger n8n error handling
        },
      },
    },
  },
};

// IF node configuration to branch on Vex approval
const vexBranchNodeConfig = {
  name: 'Vex: Approved?',
  type: 'n8n-nodes-base.if',
  typeVersion: 2,
  position: [1100, 300],
  parameters: {
    conditions: {
      options: { caseSensitive: true, leftValue: '', typeValidation: 'strict' },
      conditions: [
        {
          leftValue: '={{ $json.approved }}',
          rightValue: true,
          operator: { type: 'boolean', operation: 'equals' },
        },
      ],
      combinator: 'and',
    },
  },
};

console.log('Vex node configs ready for n8n workflow import:', {
  vexValidationNodeConfig,
  vexBranchNodeConfig,
});

// vex-loop-detector.ts — Add these endpoints to your Vex webhook service
import { vex } from './vex-client';
import { Router, Request, Response } from 'express';

const router = Router();

// Track workflow execution counts per trigger source
const executionTracker = new Map<string, { count: number; firstSeen: number }>();

router.post('/check-loop', async (req: Request, res: Response) => {
  const { workflowId, triggerId, triggerType } = req.body as {
    workflowId: string;
    triggerId: string;
    triggerType: string;
  };

  const key = `${workflowId}:${triggerId}`;
  const now = Date.now();
  const windowMs = 60_000; // 1-minute window
  const maxExecutions = 3;

  const existing = executionTracker.get(key);

  if (existing && now - existing.firstSeen < windowMs) {
    existing.count += 1;
    if (existing.count > maxExecutions) {
      // Report recursive loop to Vex
      await vex.reportIncident({
        type: 'recursive_execution_loop',
        agentId: `n8n-workflow-${workflowId}`,
        details: {
          triggerId,
          triggerType,
          executionCount: existing.count,
          windowMs,
        },
        severity: 'critical',
      });
      return res.status(429).json({
        blocked: true,
        reason: `Recursive loop detected: workflow ${workflowId} triggered ${existing.count} times in ${windowMs}ms`,
      });
    }
  } else {
    executionTracker.set(key, { count: 1, firstSeen: now });
  }

  res.status(200).json({ blocked: false });
});

// Validate Window Buffer Memory contents before agent injection
router.post('/validate-memory', async (req: Request, res: Response) => {
  const { sessionId, workflowId, memoryMessages } = req.body as {
    sessionId: string;
    workflowId: string;
    memoryMessages: Array<{ role: string; content: string; timestamp?: number }>;
  };

  const staleThresholdMs = 30 * 60 * 1000; // 30 minutes
  const now = Date.now();

  const staleMessages = memoryMessages.filter(
    (m) => m.timestamp && now - m.timestamp > staleThresholdMs
  );

  const result = await vex.evaluate({
    sessionId,
    agentId: `n8n-workflow-${workflowId}-memory`,
    input: {
      memoryContents: memoryMessages.map((m) => m.content).join('\n'),
    },
    context: {
      staleMessageCount: staleMessages.length,
      totalMessages: memoryMessages.length,
    },
  });

  if (!result.approved || staleMessages.length > 0) {
    return res.status(422).json({
      approved: false,
      reason: staleMessages.length > 0
        ? `Memory contains ${staleMessages.length} stale messages older than 30 minutes`
        : result.rejectionReason,
      sanitizedMessages: memoryMessages.filter(
        (m) => !m.timestamp || now - m.timestamp <= staleThresholdMs
      ),
    });
  }

  res.status(200).json({ approved: true, messages: memoryMessages });
});

export { router as vexLoopRouter };
